# Log diagnostics in a HuggingFace Trainer callback
class DPODiagnosticsCallback:
    def on_log(self, args, state, control, logs=None, **kwargs):
        if not logs:
            return
        margin = logs.get('rewards/margins', None)
        acc    = logs.get('rewards/accuracies', None)
        if margin is not None and margin < 0:
            print(f"[DPO] WARNING: negative reward margin {margin:.3f}")
        if acc is not None and acc < 0.5:
            print(f"[DPO] WARNING: accuracy below chance {acc:.3f}")

def ipo_loss(
    chosen_rewards: torch.Tensor,    # implicit rewards from dpo_loss step
    rejected_rewards: torch.Tensor,
    beta: float = 0.1,
) -> torch.Tensor:
    """IPO replaces log-sigmoid with a squared target-margin loss."""
    target_margin = 1.0 / (2.0 * beta)
    margins = chosen_rewards - rejected_rewards
    return ((margins - target_margin) ** 2).mean()
